// KEIS 公買搶單 watcher（每 30 秒觸發，自己卡早上時段）
// 需要 Railway/n8n 環境變數：KEIS_USERNAME、KEIS_PASSWORD
// 認證：POST /auth/login 取 JWT（token_type=bearer, 8h），之後帶 Authorization: Bearer
const helpers = this.helpers;
const BASE = "https://keis.kshouse.com.tw/api/v1";
const ORIGIN = "https://keis.kshouse.com.tw";

// ===== 設定 =====
const CITIES = ["高雄市"];        // 只搶這些縣市；空陣列=不限
const PROPERTY_TYPES = [];        // 物件類型(中文)白名單；空=全收
const INQUIRY_TYPE = 1;           // 1=買屋, 2=租屋
const WINDOWS = [["07:50", "09:30"]]; // 只在這些時段動作（台北時間）
const USER_ID = "Ufab42c56b2eb9b9a9ff18c367b85a6dd"; // 薛力瑜 LINE userId
// ================

// 時段檢查（台北時間）
const tpe = new Date(new Date().toLocaleString('en-US', { timeZone: 'Asia/Taipei' }));
const cur = tpe.getHours() * 60 + tpe.getMinutes();
const inWin = WINDOWS.some(([s, e]) => {
  const [sh, sm] = s.split(':').map(Number);
  const [eh, em] = e.split(':').map(Number);
  return cur >= sh * 60 + sm && cur <= eh * 60 + em;
});
if (!inWin) return [];

// 每日重置已處理清單；快取 token
const sd = $getWorkflowStaticData('global');
const today = tpe.toISOString().slice(0, 10);
if (sd.keis_seen_day !== today) { sd.keis_seen_day = today; sd.keis_seen = []; }
const seen = new Set(sd.keis_seen);

async function login() {
  return await helpers.httpRequest({
    method: 'POST',
    url: `${BASE}/auth/login?device_type=desktop`,
    headers: { 'content-type': 'application/x-www-form-urlencoded', origin: ORIGIN, referer: `${ORIGIN}/login` },
    body: `username=${encodeURIComponent($env.KEIS_USERNAME)}&password=${encodeURIComponent($env.KEIS_PASSWORD)}`,
  });
}

let token = sd.keis_token;
if (!token || Date.now() > (sd.keis_token_exp || 0) - 60000) {
  const lg = await login();
  token = lg.access_token;
  sd.keis_token = token;
  sd.keis_token_exp = Date.now() + ((lg.expires_in || 28800) * 1000);
}
const AUTH = { authorization: `Bearer ${token}`, origin: ORIGIN, referer: `${ORIGIN}/public-purchase` };

// 撈買屋清單
const year = tpe.getFullYear();
const qs = new URLSearchParams({
  page: '1', page_size: '20', inquiry_type: String(INQUIRY_TYPE), only_my_applications: 'false',
  start_date: `${year}-01-01 00:00:00`, end_date: `${year}-12-31 23:59:59`, target_area: '', property_category: '',
}).toString();
const body = await helpers.httpRequest({ method: 'GET', url: `${BASE}/call-purchase/query?${qs}`, headers: AUTH });
const records = body.data || [];
let quota = body.new_case_quota_remaining;
quota = (quota == null) ? 0 : quota;
if (quota <= 0) return [];

// 篩選 + 由新到舊
const fmtB = (r) => { const s = r.budget_start || 0, e = r.budget_end || 0; if (!s && !e) return '-'; if (e && e !== s) return `${s}-${e}萬`; return `${s}萬${e ? '' : '以上'}`; };
const cands = records
  .filter(r => r.status === 'Available'
    && (CITIES.length === 0 || CITIES.includes(r.target_city))
    && (PROPERTY_TYPES.length === 0 || PROPERTY_TYPES.includes(r.property_category))
    && !seen.has(r.summary_id))
  .sort((a, b) => (b.start_time || '').localeCompare(a.start_time || ''));
if (cands.length === 0) return [];

// 搶單（受配額夾住）
const grabbed = [];
for (const r of cands) {
  if (quota - grabbed.length <= 0) break;
  seen.add(r.summary_id);
  try {
    const ar = await helpers.httpRequest({ method: 'POST', url: `${BASE}/call-purchase/apply/${r.summary_id}`, headers: AUTH });
    if (ar && ar.success) {
      const d = ar.data || {};
      grabbed.push({ summary_id: r.summary_id, name: d.display_name || '', phone: d.phone_number || '', city: r.target_city, category: r.property_category, budget: fmtB(r) });
    }
  } catch (e) { /* 被秒搶/配額用完 → 跳過 */ }
}
sd.keis_seen = [...seen];
if (grabbed.length === 0) return [];

const lines = grabbed.map(g => `・${g.name} ${g.phone}｜${g.city} ${g.category} ${g.budget}`).join('\n');
const text = `🔔 公買搶到 ${grabbed.length} 筆（今日剩餘配額 ${quota - grabbed.length}）\n\n${lines}`;
return [{ json: { userId: USER_ID, summaryText: text, grabbed } }];
